void PrintDeviceProperties(){
    cl_platform_id platform;
    cl_device_id device;
    cl_uint num_platforms;
    cl_uint num_devices;
    cl_int status;

    status = clGetPlatformIDs(1, &platform, &num_platforms);
    if (status != CL_SUCCESS || num_platforms == 0) {
        printf("No OpenCL platforms found.\n");
        return;
    }

    status = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 0, NULL, &num_devices);
    if (status != CL_SUCCESS || num_devices == 0) {
        printf("No OpenCL devices found.\n");
        return;
    }

    cl_device_id *devices = (cl_device_id*)malloc(num_devices * sizeof(cl_device_id));
    status = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, num_devices, devices, NULL);
    if (status != CL_SUCCESS) {
        free(devices);
        return;
    }

    printf("Total Device found: %d\n", num_devices);

    for (cl_uint i = 0; i < num_devices; ++i) {
        char name[256];
        char vendor[256];
        cl_ulong global_mem;
        cl_ulong local_mem;
        size_t max_threads;
        size_t max_dims[3];
        cl_uint clock;

        clGetDeviceInfo(devices[i], CL_DEVICE_NAME, sizeof(name), name, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_VENDOR, sizeof(vendor), vendor, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(global_mem), &global_mem, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_LOCAL_MEM_SIZE, sizeof(local_mem), &local_mem, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(max_threads), &max_threads, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_MAX_WORK_ITEM_DIMENSIONS, sizeof(max_dims), max_dims, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_MAX_WORK_ITEM_sizes, sizeof(max_dims), max_dims, NULL);
        clGetDeviceInfo(devices[i], CL_DEVICE_MAX_CLOCK_FREQUENCY, sizeof(clock), &clock, NULL);

        printf("\nDevice Name \t\t - %s ", name);
        printf("\n**************************************");
        printf("\nTotal Global Memory\t\t\t - %lu KB", global_mem/1024);
        printf("\nShared memory available per block \t - %lu KB", local_mem/1024);
        printf("\nNumber of registers per thread block \t - N/A");
        printf("\nWarp size in threads \t\t\t - N/A");
        printf("\nMemory Pitch \t\t\t\t - N/A");
        printf("\nMaximum threads per block \t\t - %zu", max_threads);
        printf("\nMaximum Thread Dimension (block) \t - %zu %zu %zu", max_dims[0], max_dims[1], max_dims[2]);
        printf("\nMaximum Thread Dimension (grid) \t - N/A N/A N/A");
        printf("\nTotal constant memory \t\t\t - N/A");
