			*(m+i) = 0.0;
}









void ForwardSub()
{
	int t;
    cl_mem m_cl, a_cl, b_cl;
    cl_int err;

    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue queue;
    cl_program program;
    cl_kernel kernel_fan1, kernel_fan2;

    cl_uint num_platforms;
    err = clGetPlatformIDs(1, &platform, &num_platforms);
    checkCLError("Get Platform IDs", err);

    err = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, NULL);
    checkCLError("Get Device IDs", err);

    context = clCreateContext(NULL, 1, &device, NULL, NULL, &err);
    checkCLError("Create Context", err);

    queue = clCreateCommandQueue(context, device, 0, &err);
    checkCLError("Create Command Queue", err);

    const char *kernel_source = 
        "__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t) {\n"
        "    int idx = get_global_id(0);\n"
        "    if(idx >= Size-1-t) return;\n"
        "    m_cuda[Size*(idx+t+1)+t] = a_cuda[Size*(idx+t+1)+t] / a_cuda[Size*t+t];\n"
        "}\n"
        "\n"
        "__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t) {\n"
        "    int xidx = get_global_id(0);\n"
        "    int yidx = get_global_id(1);\n"
        "    \n"
        "    if(xidx >= Size-1-t) return;\n"
        "    if(yidx >= Size-t) return;\n"
        "    \n"
        "    a_cuda[Size*(xidx+1+t)+(yidx+t)] -= m_cuda[Size*(xidx+1+t)+t] * a_cuda[Size*t+(yidx+t)];\n"
        "    \n"
        "    if(yidx == 0){\n"
        "        b_cuda[xidx+1+t] -= m_cuda[Size*(xidx+1+t)+t] * b_cuda[t];\n"
        "    }\n"
        "}\n";

    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &err);
    checkCLError("Create Program", err);

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    checkCLError("Build Program", err);

    kernel_fan1 = clCreateKernel(program, "Fan1", &err);
    checkCLError("Create Kernel Fan1", err);

    kernel_fan2 = clCreateKernel(program, "Fan2", &err);
    checkCLError("Create Kernel Fan2", err);

    m_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
    checkCLError("Create Buffer m", err);

    a_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * Size * sizeof(float), NULL, &err);
    checkCLError("Create Buffer a", err);

    b_cl = clCreateBuffer(context, CL_MEM_READ_WRITE, Size * sizeof(float), NULL, &err);
    checkCLError("Create Buffer b", err);

    clEnqueueWriteBuffer(queue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);

    int block_size, grid_size;

    block_size = MAXBLOCKSIZE;
    if (block_size > Size) block_size = Size;
    grid_size = (Size + block_size - 1) / block_size;

    size_t global_size_1 = (size_t)grid_size * block_size;

    int blockSize2d, gridSize2d;
    blockSize2d = BLOCK_SIZE_XY;
    if (blockSize2d > Size) blockSize2d = Size;
    gridSize2d = (Size + blockSize2d - 1) / blockSize2d; 

    size_t global_size_2_x = (size_t)gridSize2d * blockSize2d;
    size_t global_size_2_y = (size_t)gridSize2d * blockSize2d;

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    struct timeval time_start;
    gettimeofday(&time_start, NULL);

    for (t=0; t<(Size-1); t++) {
        int arg_j1 = Size - t;
        int range_x = Size - 1 - t;
        int range_y = Size - t;

        // Adjust global sizes for current iteration to avoid launching excessive threads
        size_t current_gs_1 = (range_x > 0) ? ((range_x + block_size - 1) / block_size) * block_size : 1;
        size_t current_gs_2_x = (range_x > 0) ? ((range_x + blockSize2d - 1) / blockSize2d) * blockSize2d : 1;
        size_t current_gs_2_y = (range_y > 0) ? ((range_y + blockSize2d - 1) / blockSize2d) * blockSize2d : 1;

        if (range_x <= 0) {
            // No work to do for Fan1/Fan2 in this step if range is 0 or negative
            continue;
        }

        clSetKernelArg(kernel_fan1, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernel_fan1, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernel_fan1, 2, sizeof(int), &Size);
        clSetKernelArg(kernel_fan1, 3, sizeof(int), &t);

        err = clEnqueueRunKernel(queue, kernel_fan1, 1, NULL, &current_gs_1, NULL, 0, NULL, NULL);
        checkCLError("Run Kernel Fan1", err);

        clSetKernelArg(kernel_fan2, 0, sizeof(cl_mem), &m_cl);
        clSetKernelArg(kernel_fan2, 1, sizeof(cl_mem), &a_cl);
        clSetKernelArg(kernel_fan2, 2, sizeof(cl_mem), &b_cl);
        clSetKernelArg(kernel_fan2, 3, sizeof(int), &Size);
        clSetKernelArg(kernel_fan2, 4, sizeof(int), &arg_j1);
        clSetKernelArg(kernel_fan2, 5, sizeof(int), &t);

        err = clEnqueueRunKernel(queue, kernel_fan2, 2, NULL, &current_gs_2_x, &current_gs_2_y, 0, NULL, NULL);
        checkCLError("Run Kernel Fan2", err);

        clFinish(queue);
    }

    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
    tvsub(&time_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    clEnqueueReadBuffer(queue, m_cl, CL_TRUE, 0, Size * Size * sizeof(float), m, 0, NULL, NULL);
    clEnqueueReadBuffer(queue, a_cl, CL_TRUE, 0, Size * Size * sizeof(float), a, 0, NULL, NULL);
    clEnqueueReadBuffer(queue, b_cl, CL_TRUE, 0, Size * sizeof(float), b, 0, NULL, NULL);

    clReleaseMemObject(m_cl);
    clReleaseMemObject(a_cl);
    clReleaseMemObject(b_cl);
    clReleaseKernel(kernel_fan1);
    clReleaseKernel(kernel_fan2);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);
}






void BackSub()
{

	finalVec = (float *) malloc(Size * sizeof(float));

	int i,j;
	for(i=0;Size > i;i++){
		finalVec[Size-i-1]=b[Size-i-1];
		for(j=0;i > j;j++)
		{
			finalVec[Size-i-1]-=*(a+Size*(Size-i-1)+(Size-j-1)) * finalVec[Size-j-1];
		}
		finalVec[Size-i-1]=finalVec[Size-i-1]/ *(a+Size*(Size-i-1)+(Size-i-1));
	}
}

